"""Blatter inverse solver using the TAO library.

Provides a Tikhonov-based inverse solver that uses the Blatter
forward problem instead of SSA.
"""

import PISM
from PISM.util import Bunch
from PISM.logging import logError
from PISM.invert.ssa import InvSSASolver

import sys
import traceback


class BlatterTaucIterationListenerAdaptor(
        PISM.IP_BlatterTaucTaoTikhonovProblemListener):
    """Adaptor converting C++ Blatter Tikhonov iteration callbacks to Python.

    Parameters
    ----------
    owner : InvBlatterSolver_Tikhonov
        The solver that owns this adaptor.
    listener : callable
        The Python listener to forward events to.
    """

    def __init__(self, owner, listener):
        PISM.IP_BlatterTaucTaoTikhonovProblemListener.__init__(self)
        self.owner = owner
        self.listener = listener

    def iteration(self, *args):
        """Called during iterations. Packs arguments into a Bunch."""
        try:
            if len(args) == 12:
                problem, eta, it, objVal, penaltyVal, d, diff_d, grad_d, u, diff_u, grad_u, grad = args
            else:
                logError("Unexpected number of arguments in iteration callback: %d\n" % len(args))
                return
            data = Bunch(tikhonov_penalty=eta, JDesign=objVal, JState=penaltyVal,
                         zeta=d, zeta_step=diff_d, grad_JDesign=grad_d,
                         u=u, residual=diff_u, grad_JState=grad_u,
                         grad_JTikhonov=grad)
            self.listener(self.owner, it, data)
        except Exception:
            logError("\nERROR: Exception occurred during a Blatter inverse"
                     " solver listener callback:\n\n")
            traceback.print_exc(file=sys.stdout)
            raise


class InvBlatterSolver_Tikhonov(InvSSASolver):
    """Blatter inverse solver based on Tikhonov minimization using TAO.

    Parameters
    ----------
    blatterrun : BlatterForwardRun
        The Blatter forward problem setup.
    method : str
        TAO algorithm name (e.g., ``'tikhonov_lmvm'``, ``'tikhonov_cg'``).
    """

    tao_types = {}
    if PISM.PETSc.Sys.getVersion() < (3, 5, 0):
        tao_types = {'tikhonov_lmvm': 'tao_lmvm',
                     'tikhonov_cg': 'tao_cg',
                     'tikhonov_blmvm': 'tao_blmvm'}
    else:
        tao_types = {'tikhonov_lmvm': 'lmvm',
                     'tikhonov_cg': 'cg',
                     'tikhonov_blmvm': 'blmvm'}

    def __init__(self, blatterrun, method):
        InvSSASolver.__init__(self, blatterrun, method)
        self.listeners = []
        self.solver = None
        self.ip = None
        if self.tao_types.get(method) is None:
            raise ValueError("Unknown TAO Tikhonov method: %s" % method)

    def addIterationListener(self, listener):
        """Add a listener called after each iteration."""
        self.listeners.append(listener)

    def addDesignUpdateListener(self, listener):
        """Add a listener called after each design variable update."""
        self.listeners.append(listener)

    def solveForward(self, zeta, out=None):
        r"""Solve the Blatter system for a given :math:`\zeta`.

        Parameters
        ----------
        zeta : Array
            Parameterized design variable.
        out : Array, optional
            Storage for the result.

        Returns
        -------
        Array
            The surface velocity solution.
        """
        ssa = self.run.solver
        reason = ssa.linearize_at(zeta)
        if reason.failed():
            raise PISM.AlgorithmFailureException(reason)
        if out is not None:
            out.copy_from(ssa.solution())
        else:
            out = ssa.solution()
        return out

    def solveInverse(self, zeta0, u_obs, zeta_inv):
        r"""Execute the Blatter Tikhonov inversion.

        Parameters
        ----------
        zeta0 : Array
            Prior guess for the parameterized design variable.
        u_obs : array::Vector
            Observed surface velocities.
        zeta_inv : Array
            Starting value for the minimization.

        Returns
        -------
        TerminationReason
            Reason the solver terminated.
        """
        eta = self.config.get_number("inverse.tikhonov.penalty_weight")

        design_var = self.run.designVariable()
        if design_var == 'tauc':
            problemClass = PISM.IP_BlatterTaucTaoTikhonovProblem
            solverClass = PISM.IP_BlatterTaucTaoTikhonovSolver
            listenerClass = BlatterTaucIterationListenerAdaptor
        else:
            raise RuntimeError(
                "Unsupported design variable '%s' for Blatter inversion."
                " Only 'tauc' is currently supported." % design_var)

        tao_type = self.tao_types[self.method]
        (stateFunctional, designFunctional) = \
            PISM.invert.ssa.createTikhonovFunctionals(self.run)

        self.ip = problemClass(self.run.solver, zeta0, u_obs, eta,
                               stateFunctional, designFunctional)
        self.solver = solverClass(self.run.grid.com, tao_type, self.ip)

        max_it = int(self.config.get_number("inverse.max_iterations"))
        self.solver.setMaximumIterations(max_it)

        pl = [listenerClass(self, l) for l in self.listeners]
        for l in pl:
            self.ip.addListener(l)

        self.ip.setInitialGuess(zeta_inv)

        vecs = self.run.modeldata.vecs
        if vecs.has('zeta_fixed_mask'):
            self.run.solver.set_tauc_fixed_locations(vecs.zeta_fixed_mask)

        return self.solver.solve()

    def inverseSolution(self):
        """Return the (zeta, u) solution pair."""
        zeta = self.ip.designSolution()
        u = self.ip.stateSolution()
        return (zeta, u)
